{
  "sentences": [
    {
      "text": "你好，我想要一杯小杯拿鐵，可以嗎？",
      "pinyin": "Nǐ hǎo, wǒ xiǎng yào yī bēi xiǎo bēi nátiě, kěyǐ ma?",
      "pinyin_numeric": "ni3 hao3, wo3 xiang3 yao4 yi1 bei1 xiao3 bei1 na2tie3, ke3yi3 ma0?",
      "translation_en": "Hello, I would like a small latte, okay?",
      "translation_ko": "안녕하세요, 작은 라떼 한 잔을 원하는데 괜찮을까요?"
    },
    {
      "text": "可以幫我加珍珠嗎？",
      "pinyin": "Kěyǐ bāng wǒ jiā zhēnzhū ma?",
      "pinyin_numeric": "ke3yi3 bang1 wo3 jia1 zhen1zhu1 ma0?",
      "translation_en": "Can you add boba for me?",
      "translation_ko": "타피오카 펄을 추가해 주시겠어요?"
    },
    {
      "text": "我想要一杯冰的紅茶，半糖，可以嗎？",
      "pinyin": "Wǒ xiǎng yào yī bēi bīng de hóngchá, bàn táng, kěyǐ ma?",
      "pinyin_numeric": "wo3 xiang3 yao4 yi1 bei1 bing1 de0 hong2cha2, ban4 tang2, ke3yi3 ma0?",
      "translation_en": "I would like an iced black tea, half sugar, okay?",
      "translation_ko": "얼음 홍차 한 잔, 반 당으로 주시겠어요?"
    },
    {
      "text": "可以給我一個袋子嗎？謝謝。",
      "pinyin": "Kěyǐ gěi wǒ yī ge dàizi ma? Xièxie.",
      "pinyin_numeric": "ke3yi3 gei3 wo3 yi1 ge0 dai4zi0 ma0? xie4xie0.",
      "translation_en": "Can you give me a bag? Thank you.",
      "translation_ko": "봉투 하나 주시겠어요? 감사합니다."
    },
    {
      "text": "不好意思，可以再說一次嗎？慢一點。",
      "pinyin": "Bù hǎoyìsi, kěyǐ zài shuō yī cì ma? Màn yī diǎn.",
      "pinyin_numeric": "bu4 hao3yi4si0, ke3yi3 zai4 shuo1 yi1 ci4 ma0? man4 yi1 dian3.",
      "translation_en": "Excuse me, can you say it again? Slower.",
      "translation_ko": "죄송합니다만, 한 번 더 말씀해 주시겠어요? 천천히요."
    },
    {
      "text": "可以幫我外帶一杯豆漿嗎？",
      "pinyin": "Kěyǐ bāng wǒ wàidài yī bēi dòujiāng ma?",
      "pinyin_numeric": "ke3yi3 bang1 wo3 wai4dai4 yi1 bei1 dou4jiang1 ma0?",
      "translation_en": "Can you help me get a soy milk to go?",
      "translation_ko": "두유 한 잔 포장해 주시겠어요?"
    },
    {
      "text": "我想要一杯中杯的綠茶，去冰，可以嗎？",
      "pinyin": "Wǒ xiǎng yào yī bēi zhōng bēi de lǜchá, qù bīng, kěyǐ ma?",
      "pinyin_numeric": "wo3 xiang3 yao4 yi1 bei1 zhong1 bei1 de0 lü4cha2, qu4 bing1, ke3yi3 ma0?",
      "translation_en": "I would like a medium green tea, no ice, okay?",
      "translation_ko": "중간 컵 녹차 한 잔, 얼음 빼고 주시겠어요?"
    },
    {
      "text": "可以給我一根吸管嗎？麻煩你。",
      "pinyin": "Kěyǐ gěi wǒ yī gēn xīguǎn ma? Máfan nǐ.",
      "pinyin_numeric": "ke3yi3 gei3 wo3 yi1 gen1 xi1guan3 ma0? ma2fan0 ni3.",
      "translation_en": "Can you give me a straw? Please.",
      "translation_ko": "빨대 하나 주시겠어요? 부탁드립니다."
    },
    {
      "text": "不好意思，這個價錢可以幫我看一下嗎？",
      "pinyin": "Bù hǎoyìsi, zhège jiàqián kěyǐ bāng wǒ kàn yīxià ma?",
      "pinyin_numeric": "bu4 hao3yi4si0, zhe4ge0 jia4qian2 ke3yi3 bang1 wo3 kan4 yi1xia4 ma0?",
      "translation_en": "Excuse me, can you check this price for me?",
      "translation_ko": "죄송합니다만, 이 가격 좀 확인해 주시겠어요?"
    },
    {
      "text": "可以內用嗎？我想要一杯大杯拿鐵。",
      "pinyin": "Kěyǐ nèiyòng ma? Wǒ xiǎng yào yī bēi dà bēi nátiě.",
      "pinyin_numeric": "ke3yi3 nei4yong4 ma0? wo3 xiang3 yao4 yi1 bei1 da4 bei1 na2tie3.",
      "translation_en": "Can I dine in? I would like a large latte.",
      "translation_ko": "매장에서 먹을 수 있나요? 큰 라떼 한 잔 원합니다."
    }
  ]
}
